import React from 'react';
import { TextFieldGroup, TextField } from '@salutejs/plasma-web';
export function App() {
    return (
        <TextFieldGroup>
            {Array(5)
                .fill(true)
                .map((_, i) => (
                    <TextField placeholder={`input #${i}`} />
                ))}
        </TextFieldGroup>
    );
}

import React from 'react';
import { TextFieldGroup, TextField } from '@salutejs/plasma-web';
